<?php

namespace Database\Seeders;

use App\Models\PariwisataSurveyQuestion;
use App\Models\SurveyTemplate;
use App\Models\User;
use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;
use JsonException;

class PariwisataSurveySeeder extends Seeder
{
    /**
     * @throws JsonException
     */
    public function run(): void
    {
        DB::transaction(function (): void {
            $user = User::query()->firstOrCreate(
                ['email' => 'admin@desa-wisata-bca.test'],
                [
                    'name' => 'Admin CSR',
                    'password' => 'password',
                    'role' => 'admin',
                    'status' => 'active',
                ],
            );

            $template = SurveyTemplate::withTrashed()->firstOrNew([
                'title' => 'Matrix Sertifikasi Desa Wisata Berkelanjutan - Pariwisata',
            ]);
            $shouldRestore = $template->exists && $template->trashed();

            $template->fill([
                'description' => 'Template survey pariwisata hasil konversi dokumen Pedoman Pariwisata Berkelanjutan kategori A, B, C, dan D.',
                'status' => 'published',
                'created_by' => $user->id,
                'published_at' => now(),
            ]);
            $template->save();

            if ($shouldRestore) {
                $template->restore();
            }

            $template->pariwisataSurveyQuestions()
                ->withTrashed()
                ->get()
                ->each(function (PariwisataSurveyQuestion $question): void {
                    $question->options()->withTrashed()->forceDelete();
                    $question->forceDelete();
                });

            foreach ($this->rows() as $index => $row) {
                $question = $template->pariwisataSurveyQuestions()->create([
                    'category_code' => $row['category_code'],
                    'category_name' => $row['category_name'],
                    'sub_category_code' => $row['sub_category_code'],
                    'sub_category_name' => $row['sub_category_name'],
                    'criteria_code' => $row['criteria_code'],
                    'criteria_name' => $row['criteria_name'],
                    'criteria_description' => $row['criteria_description'],
                    'indicator_code' => $row['indicator_code'],
                    'indicator_name' => $row['indicator_name'],
                    'indicator_description' => $row['indicator_description'],
                    'supporting_evidence' => $row['supporting_evidence'],
                    'input_type' => $row['input_type'],
                    'document_required' => $row['document_required'],
                    'document_hint' => $row['document_hint'],
                    'sort_order' => $index + 1,
                    'is_active' => true,
                ]);

                foreach ($this->options($row['options']) as $sortOrder => $option) {
                    $question->options()->create([
                        'score' => $option['score'],
                        'level' => $option['level'],
                        'label' => $option['label'],
                        'description' => $option['description'],
                        'sort_order' => $sortOrder + 1,
                    ]);
                }
            }
        });
    }

    /**
     * @return array<int, array<string, mixed>>
     *
     * @throws JsonException
     */
    private function rows(): array
    {
        return json_decode(self::SOURCE_ROWS, true, 512, JSON_THROW_ON_ERROR);
    }

    /**
     * @param  array<string, string>  $descriptions
     * @return array<int, array{score: int, level: string, label: string, description: string}>
     */
    private function options(array $descriptions): array
    {
        return [
            [
                'score' => 4,
                'level' => 'terpenuhi_sepenuhnya',
                'label' => 'Terpenuhi Sepenuhnya',
                'description' => $descriptions['4'],
            ],
            [
                'score' => 3,
                'level' => 'sebagian_terpenuhi',
                'label' => 'Sebagian Terpenuhi',
                'description' => $descriptions['3'],
            ],
            [
                'score' => 2,
                'level' => 'kurang_terpenuhi',
                'label' => 'Kurang Terpenuhi',
                'description' => $descriptions['2'],
            ],
            [
                'score' => 1,
                'level' => 'tidak_terpenuhi',
                'label' => 'Tidak Terpenuhi',
                'description' => $descriptions['1'],
            ],
        ];
    }

